const fs = require('fs');
const alert = $input.first().json;
const ns = alert.namespace || 'olympus';
const pod = alert.pod || '';

let token = '';
try {
  token = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/token', 'utf8').trim();
} catch (e) {
  return [{ json: { ...alert, k8s_context: 'No K8s token available: ' + e.message } }];
}

const headers = { 'Authorization': 'Bearer ' + token };
let contextLines = [];

try {
  if (pod) {
    const logResp = await fetch(
      'https://kubernetes.default.svc/api/v1/namespaces/' + ns + '/pods/' + pod + '/log?tailLines=50',
      { headers }
    );
    const logs = await logResp.text();
    contextLines.push('=== Pod logs: ' + pod + ' ===');
    contextLines.push(logs.substring(0, 3000));
  } else {
    const podsResp = await fetch(
      'https://kubernetes.default.svc/api/v1/namespaces/' + ns + '/pods',
      { headers }
    );
    const podsData = await podsResp.json();
    const pods = (podsData.items || []).slice(0, 3);
    for (const p of pods) {
      const pName = p.metadata.name;
      const logResp = await fetch(
        'https://kubernetes.default.svc/api/v1/namespaces/' + ns + '/pods/' + pName + '/log?tailLines=20',
        { headers }
      );
      contextLines.push('=== ' + pName + ' (tail 20) ===');
      contextLines.push((await logResp.text()).substring(0, 500));
    }
  }

  if (ns === 'databases' || alert.alertname.toLowerCase().includes('backup')) {
    const jobsResp = await fetch(
      'https://kubernetes.default.svc/apis/batch/v1/namespaces/databases/jobs',
      { headers }
    );
    const jobsData = await jobsResp.json();
    const recentJobs = (jobsData.items || [])
      .sort((a, b) => new Date(b.metadata.creationTimestamp) - new Date(a.metadata.creationTimestamp))
      .slice(0, 3)
      .map(j => j.metadata.name + ': ' + (j.status.succeeded ? 'succeeded' : j.status.failed ? 'failed' : 'active'));
    contextLines.push('=== Recent backup jobs ===');
    contextLines.push(recentJobs.join('\n'));
  }
} catch (e) {
  contextLines.push('K8s API error: ' + e.message);
}

return [{ json: { ...alert, k8s_context: contextLines.join('\n') } }];
